// FIX H4: Verificacion de firma HMAC. 
// Nota: n8n sandbox no expone crypto module directamente;
// la comparacion timing-safe se implementa comparando char por char con igual tiempo.
const received = $('Webhook - Cal.com Booking').item.json.headers['x-cal-signature-256'] || '';
const expected = $input.first().json.computed_signature || '';

// Implementacion timing-safe sin modulo crypto (compatible con sandbox n8n)
// Compara longitud primero, luego XOR caracter a caracter
if (!received) {
  throw new Error('[calcom] Header x-cal-signature-256 ausente — request rechazado');
}

if (received.length !== expected.length) {
  throw new Error('[calcom] Firma invalida — longitud no coincide');
}

let diff = 0;
for (let i = 0; i < expected.length; i++) {
  diff |= received.charCodeAt(i) ^ expected.charCodeAt(i);
}

if (diff !== 0) {
  throw new Error(`[calcom] Firma HMAC invalida — request rechazado`);
}

// Firma valida: retornar el body del evento
const body = $('Webhook - Cal.com Booking').item.json.body;
return [{ json: body }];

